public struct FfiConverterTypeTerminalRenderer: FfiConverter {

    typealias FfiType = UnsafeMutableRawPointer
    typealias SwiftType = TerminalRenderer

    public static func lift(_ pointer: UnsafeMutableRawPointer) throws -> TerminalRenderer {
