public protocol PtyCallback : AnyObject {
    
    func onData(id: UInt32, data: Data) 
    
    func onExit(id: UInt32, exitCode: Int32) 
    
}

// Magic number for the Rust proxy to call using the same mechanism as every other method,
// to free the callback once it's dropped by Rust.
private let IDX_CALLBACK_FREE: Int32 = 0
// Callback return codes
private let UNIFFI_CALLBACK_SUCCESS: Int32 = 0
private let UNIFFI_CALLBACK_ERROR: Int32 = 1
private let UNIFFI_CALLBACK_UNEXPECTED_ERROR: Int32 = 2

// Put the implementation in a struct so we don't pollute the top-level namespace
fileprivate struct UniffiCallbackInterfacePtyCallback {

    // Create the VTable using a series of closures.
    // Swift automatically converts these into C callback functions.
    static var vtable: UniffiVTableCallbackInterfacePtyCallback = UniffiVTableCallbackInterfacePtyCallback(
        onData: { (
            uniffiHandle: UInt64,
            id: UInt32,
            data: RustBuffer,
            uniffiOutReturn: UnsafeMutableRawPointer,
            uniffiCallStatus: UnsafeMutablePointer<RustCallStatus>
        ) in
            let makeCall = {
                () throws -> () in
                guard let uniffiObj = try? FfiConverterCallbackInterfacePtyCallback.handleMap.get(handle: uniffiHandle) else {
                    throw UniffiInternalError.unexpectedStaleHandle
                }
                return uniffiObj.onData(
                     id: try FfiConverterUInt32.lift(id),
                     data: try FfiConverterData.lift(data)
                )
            }

            
            let writeReturn = { () }
            uniffiTraitInterfaceCall(
                callStatus: uniffiCallStatus,
                makeCall: makeCall,
                writeReturn: writeReturn
            )
        },
        onExit: { (
            uniffiHandle: UInt64,
            id: UInt32,
            exitCode: Int32,
            uniffiOutReturn: UnsafeMutableRawPointer,
            uniffiCallStatus: UnsafeMutablePointer<RustCallStatus>
        ) in
            let makeCall = {
                () throws -> () in
                guard let uniffiObj = try? FfiConverterCallbackInterfacePtyCallback.handleMap.get(handle: uniffiHandle) else {
                    throw UniffiInternalError.unexpectedStaleHandle
                }
                return uniffiObj.onExit(
                     id: try FfiConverterUInt32.lift(id),
                     exitCode: try FfiConverterInt32.lift(exitCode)
                )
            }

            
            let writeReturn = { () }
            uniffiTraitInterfaceCall(
                callStatus: uniffiCallStatus,
                makeCall: makeCall,
                writeReturn: writeReturn
            )
        },
        uniffiFree: { (uniffiHandle: UInt64) -> () in
            let result = try? FfiConverterCallbackInterfacePtyCallback.handleMap.remove(handle: uniffiHandle)
            if result == nil {
                print("Uniffi callback interface PtyCallback: handle missing in uniffiFree")
            }
        }
    )
}

private func uniffiCallbackInitPtyCallback() {
    uniffi_bunnyshell_core_fn_init_callback_vtable_ptycallback(&UniffiCallbackInterfacePtyCallback.vtable)
}

